1	export type Item = Record<string, unknown>;
2	export type QuoteStep = { op: "quote"; items: Item[] };
3	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
4	export type Step = QuoteStep | ClaimStep;
5	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
6	export type QuoteResult = { premium: number };
7	export type ClaimResult = { payout: number; remainingCap: number };
8	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const itemBasePremium = (item: Item): number =>
21	  BASE_PREMIUM_BY_TYPE[item.type as string] ?? 0;
22	
23	const quotePremium = (items: Item[]): number => {
24	  const baseSum = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
25	  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
26	  return Math.ceil(baseSum + firstInsuranceSurcharge + PROCESSING_FEE);
27	};
28	
29	export const runScenario = (scenario: Scenario): ScenarioResult => {
30	  const results = scenario.steps.map((step) => {
31	    if (step.op === "quote") {
32	      return { premium: quotePremium(step.items) };
33	    }
34	    return { payout: 0, remainingCap: 0 };
35	  });
36	  return { results };
37	};
