const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type as string] ?? 0;

const itemPremiumWithFirstInsuranceSurcharge = (item: Item): number => {
  const base = itemBasePremium(item);
  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = items.reduce(
    (sum, item) => sum + itemPremiumWithFirstInsuranceSurcharge(item),
    0,
  );
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};
